   122→// ─── Server ───────────────────────────────────────────────────────────────────
   123→
   124→export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
   125→  // Strip CLAUDECODE so spawned sessions are not blocked by nested-session detection
   126→  delete process.env.CLAUDECODE;
   127→
   128→  const db = await getDb(dbPath);
   129→
   130→  // Ensure FTS table exists and is up-to-date on startup
   131→  await setupLogContentFts(db);
   132→  await syncLogContentFts(db);
   133→
   134→  const app = express();
   135→  app.use(cors());
   136→  app.use(express.json());
   137→
   138→  // Resolve git user and repo name from repo config once at startup
   139→  const gitUser  = getGitUser(repoDir);
   140→  const repoName = repoDir ? basename(repoDir) : null;
   141→
   142→  // GET /api/sessions — reconstructed from CheckpointSessionMetadata + ShadowSession
   143→  app.get("/api/sessions", async (_req, res) => {
   144→    try {
   145→      // Latest checkpoint meta per sessionId (asc order so map always ends on latest)
   146→      const allMetas = await db.checkpointSessionMetadata.findMany({
   147→        select: {
   148→          sessionId: true,
   149→          branch: true,
   150→          summary: { select: { intent: true } },
   151→        },
   152→        orderBy: { createdAt: "asc" },
   153→      });
   154→      const cpMap = new Map<string, { branch: string | null; intent: string | null }>();
   155→      for (const m of allMetas) {
   156→        cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null });
   157→      }
   158→
   159→      const shadows = await db.shadowSession.findMany();
   160→      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   161→
   162→      const allIds = [...new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)])];
   163→      if (allIds.length === 0) {
   164→        res.json([]);
   165→        return;
   166→      }
   167→
   168→      // Min/max LogEvent timestamps per session
   169→      const times = await db.logEvent.groupBy({
   170→        by: ["sessionId"],
   171→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   172→        _min: { timestamp: true },
   173→        _max: { timestamp: true },
   174→      });
   175→      const timeMap = new Map(
   176→        times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }])
   177→      );
   178→
   179→      // First cwd per session
   180→      const cwdRows = await db.logEvent.findMany({
   181→        where: { sessionId: { in: allIds }, cwd: { not: null } },
   182→        distinct: ["sessionId"],
   183→        orderBy: { id: "asc" },
   184→        select: { sessionId: true, cwd: true },
   185→      });
   186→      const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));
   187→
   188→      const result: SessionResponse[] = allIds.map((sessionId) => {
   189→        const cp     = cpMap.get(sessionId) ?? null;
   190→        const shadow = shadowMap.get(sessionId) ?? null;
   191→        const t      = timeMap.get(sessionId);
   192→        const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
   193→        const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
   194→        return {
   195→          sessionId,
   196→          startedAt: startedAt?.toISOString() ?? new Date(0).toISOString(),
   197→          updatedAt: updatedAt?.toISOString() ?? new Date(0).toISOString(),
   198→          cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
   199→          repoRoot:        repoDir ?? null,
   200→          repoName:        repoName,
   201→          parentSessionId: null,
   202→          childSessionIds: [],
   203→          gitUserName:     gitUser.name,
   204→          gitUserEmail:    gitUser.email,
   205→          prompt:          shadow?.prompt ?? null,
   206→          summary:         null,
   207→          keywords:        [],
   208→          branch:          cp?.branch ?? shadow?.gitBranch ?? null,
   209→          intent:          cp?.intent ?? null,
   210→          isLive:          shadow !== null,
   211→        };
   212→      });
   213→
   214→      result.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
   215→      res.json(result);
   216→    } catch (err) {
   217→      res.status(500).json({ error: String(err) });
   218→    }
   219→  });
   220→
   221→  // GET /api/sessions/:id
   222→  app.get("/api/sessions/:id", async (req, res) => {
   223→    try {
   224→      const id = req.params.id;
   225→      const [latestMeta, shadow, firstEvent, lastEvent] = await Promise.all([
   226→        db.checkpointSessionMetadata.findFirst({
   227→          where: { sessionId: id },
   228→          select: { branch: true, summary: { select: { intent: true } } },
   229→          orderBy: { createdAt: "desc" },
   230→        }),
   231→        db.shadowSession.findUnique({ where: { sessionId: id } }),
   232→        db.logEvent.findFirst({
   233→          where: { sessionId: id },
   234→          orderBy: { id: "asc" },
   235→          select: { cwd: true, timestamp: true },
   236→        }),
   237→        db.logEvent.findFirst({
   238→          where: { sessionId: id, timestamp: { not: null } },
   239→          orderBy: { id: "desc" },
   240→          select: { timestamp: true },
   241→        }),
   242→      ]);
   243→      if (!latestMeta && !shadow) {
   244→        res.status(404).json({ error: "Session not found" });
   245→        return;
   246→      }
   247→      const startedAt = firstEvent?.timestamp ?? shadow?.createdAt ?? null;
   248→      const updatedAt = lastEvent?.timestamp  ?? shadow?.createdAt ?? null;
   249→      res.json({
   250→        sessionId:       id,
   251→        startedAt:       startedAt?.toISOString() ?? new Date(0).toISOString(),
   252→        updatedAt:       updatedAt?.toISOString() ?? new Date(0).toISOString(),
   253→        cwd:             firstEvent?.cwd ?? shadow?.cwd ?? "",
   254→        repoRoot:        repoDir ?? null,
   255→        repoName:        repoName,
   256→        parentSessionId: null,
   257→        childSessionIds: [],
   258→        gitUserName:     gitUser.name,
   259→        gitUserEmail:    gitUser.email,
   260→        prompt:          shadow?.prompt ?? null,
   261→        summary:         null,
   262→        keywords:        [],
   263→        branch:          latestMeta?.branch ?? shadow?.gitBranch ?? null,
   264→        intent:          latestMeta?.summary?.intent ?? null,
   265→        isLive:          shadow !== null,
   266→      } satisfies SessionResponse);
   267→    } catch (err) {
   268→      res.status(500).json({ error: String(err) });
   269→    }
   270→  });
   271→
   272→  // GET /api/sessions/:id/overview
   273→  app.get("/api/sessions/:id/overview", async (req, res) => {
   274→    try {
   275→      const overview = await db.interactionOverview.findUnique({
   276→        where: { sessionId: req.params.id },
