   280→        return;
   281→      }
   282→      const result: OverviewResponse = {
   283→        sessionId: overview.sessionId,
   284→        summary: overview.summary,
   285→        keywords: overview.keywords ? (JSON.parse(overview.keywords) as string[]) : [],
   286→        startedAt: overview.startedAt.toISOString(),
   287→        endedAt: overview.endedAt.toISOString(),
   288→      };
   289→      res.json(result);
   290→    } catch (err) {
   291→      res.status(500).json({ error: String(err) });
   292→    }
   293→  });
   294→
   295→  // GET /api/sessions/:id/events
   296→  app.get("/api/sessions/:id/events", async (req, res) => {
   297→    try {
   298→      const events = await db.event.findMany({
