   325→        parentUuid:      e.parentUuid,
   326→        type:            e.type,
   327→        timestamp:       e.timestamp?.toISOString() ?? null,
   328→        cwd:             e.cwd,
   329→        gitBranch:       e.gitBranch,
   330→        slug:            e.slug,
   331→        isSidechain:     e.isSidechain,
   332→        toolUseId:       e.toolUseId,
   333→        parentToolUseId: e.parentToolUseId,
   334→        contents: e.contents.map((c) => ({
   335→          contentType:       c.contentType,
   336→          contentIndex:      c.contentIndex,
   337→          text:              c.text,
   338→          thinking:          c.thinking,
   339→          toolUseId:         c.toolUseId,
   340→          toolName:          c.toolName,
   341→          toolInput:         c.toolInput ? (JSON.parse(c.toolInput) as unknown) : null,
   342→          toolResultContent: c.toolResultContent,
   343→          isError:           c.isError,
   344→        })),
   345→        usage: e.usage ? {
   346→          model:                    e.usage.model,
   347→          stopReason:               e.usage.stopReason,
   348→          inputTokens:              e.usage.inputTokens,
   349→          outputTokens:             e.usage.outputTokens,
   350→          cacheCreationInputTokens: e.usage.cacheCreationInputTokens,
   351→          cacheReadInputTokens:     e.usage.cacheReadInputTokens,
   352→        } : null,
   353→        hookProgress: e.hookProgress ? {
   354→          type:      e.hookProgress.type,
   355→          hookEvent: e.hookProgress.hookEvent,
   356→          hookName:  e.hookProgress.hookName,
