   362→          stopReason:            e.systemData.stopReason,
   363→          preventedContinuation: e.systemData.preventedContinuation,
   364→          level:                 e.systemData.level,
   365→          durationMs:            e.systemData.durationMs,
   366→        } : null,
   367→      })));
   368→    } catch (err) {
   369→      res.status(500).json({ error: String(err) });
   370→    }
   371→  });
