   512→  // ─── V2 helpers ─────────────────────────────────────────────────────────────
   513→
   514→  type V2Session = {
   515→    summary: {
   516→      intent: string; outcome: string;
   517→      openItems: { id: number; text: string; status: string; subSessionId: string | null }[];
   518→      frictionItems: { text: string }[];
   519→      repoLearnings: { text: string }[];
   520→      codeLearnings: { path: string; finding: string }[];
   521→      workflowLearnings: { text: string }[];
   522→    } | null;
   523→  };
   524→
   525→  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   526→    return {
   527→      intent:            summary.intent,
   528→      outcome:           summary.outcome,
   529→      openItems:         summary.openItems.map((r) => ({ id: r.id, text: r.text, status: r.status, subSessionId: r.subSessionId })),
   530→      friction:          summary.frictionItems.map((r) => r.text),
   531→      repoLearnings:     summary.repoLearnings.map((r) => r.text),
   532→      codeLearnings:     summary.codeLearnings.map((r) => ({ path: r.path, finding: r.finding })),
   533→      workflowLearnings: summary.workflowLearnings.map((r) => r.text),
   534→    };
   535→  }
   536→
   537→  const V2_SESSION_INCLUDE = {
   538→    summary: {
   539→      include: {
   540→        openItems:         true,
   541→        frictionItems:     true,
   542→        repoLearnings:     true,
   543→        codeLearnings:     true,
   544→        workflowLearnings: true,
   545→      },
   546→    },
   547→  } as const;
   548→
   549→  const V2_SESSION_ORDER = { createdAt: "desc" as const };
   550→
   551→  // GET /api/v2/checkpoints
   552→  app.get("/api/v2/checkpoints", async (_req, res) => {
   553→    try {
   554→      const checkpoints = await db.checkpointMetadata.findMany({
   555→        include: {
   556→          tokenUsage: true,
   557→          filesTouched: { include: { filePath: true } },
   558→        },
   559→      });
   560→
   561→      const checkpointIds = checkpoints.map((c) => c.checkpointId);
   562→
   563→      const sessions = await db.checkpointSessionMetadata.findMany({
   564→        where:   { checkpointId: { in: checkpointIds } },
   565→        orderBy: V2_SESSION_ORDER,
   566→        include: V2_SESSION_INCLUDE,
   567→      });
   568→
   569→      // Group sessions by checkpointId
   570→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   571→      for (const s of sessions) {
   572→        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   573→        arr.push(s);
   574→        sessionsByCheckpoint.set(s.checkpointId, arr);
   575→      }
   576→
   577→      res.json(checkpoints.map((c) => {
   578→        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   579→        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
   580→        const latestCreatedAt = cpSessions
   581→          .filter((s): s is typeof s & { createdAt: Date } => s.createdAt !== null)
   582→          .map((s) => s.createdAt)
   583→          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
   584→        return {
   585→          id:               c.id,
   586→          checkpointId:     c.checkpointId,
   587→          cliVersion:       c.cliVersion,
   588→          strategy:         c.strategy,
   589→          branch:           c.branch,
   590→          checkpointsCount: c.checkpointsCount,
   591→          createdAt:        latestCreatedAt?.toISOString() ?? null,
   592→          tokenUsage: c.tokenUsage ? {
   593→            inputTokens:         c.tokenUsage.inputTokens,
   594→            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   595→            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   596→            outputTokens:        c.tokenUsage.outputTokens,
   597→            apiCallCount:        c.tokenUsage.apiCallCount,
   598→          } : null,
   599→          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   600→          sessionCount:  cpSessions.length,
   601→          summary: summary ? mapV2Summary(summary) : null,
   602→        };
   603→      }));
   604→    } catch (err) {
   605→      res.status(500).json({ error: String(err) });
   606→    }
   607→  });
   608→
   609→  // GET /api/v2/checkpoints/:id
   610→  app.get("/api/v2/checkpoints/:id", async (req, res) => {
   611→    try {
   612→      const checkpointId = req.params.id;
   613→      const checkpoint = await db.checkpointMetadata.findUnique({
   614→        where: { checkpointId },
   615→        include: {
   616→          tokenUsage: true,
   617→          filesTouched: { include: { filePath: true } },
   618→        },
   619→      });
   620→      if (!checkpoint) { res.status(404).json({ error: "Not found" }); return; }
   621→
   622→      const sessions = await db.checkpointSessionMetadata.findMany({
   623→        where:   { checkpointId },
   624→        orderBy: V2_SESSION_ORDER,
   625→        include: V2_SESSION_INCLUDE,
   626→      });
   627→
   628→      const summary = sessions.find((s) => s.summary)?.summary ?? null;
   629→
   630→      res.json({
   631→        id:               checkpoint.id,
   632→        checkpointId:     checkpoint.checkpointId,
   633→        cliVersion:       checkpoint.cliVersion,
   634→        strategy:         checkpoint.strategy,
   635→        branch:           checkpoint.branch,
   636→        checkpointsCount: checkpoint.checkpointsCount,
   637→        tokenUsage: checkpoint.tokenUsage ? {
   638→          inputTokens:         checkpoint.tokenUsage.inputTokens,
   639→          cacheCreationTokens: checkpoint.tokenUsage.cacheCreationTokens,
   640→          cacheReadTokens:     checkpoint.tokenUsage.cacheReadTokens,
   641→          outputTokens:        checkpoint.tokenUsage.outputTokens,
   642→          apiCallCount:        checkpoint.tokenUsage.apiCallCount,
   643→        } : null,
   644→        filesTouched:  checkpoint.filesTouched.map((f) => f.filePath.path),
   645→        sessionCount:  sessions.length,
   646→        summary:       summary ? mapV2Summary(summary) : null,
   647→      });
   648→    } catch (err) {
   649→      res.status(500).json({ error: String(err) });
   650→    }
   651→  });
   652→
   653→  // GET /api/v2/sessions/:id/checkpoints
   654→  app.get("/api/v2/sessions/:id/checkpoints", async (req, res) => {
   655→    try {
   656→      const sessionId = req.params.id;
   657→      const sessionRows = await db.checkpointSessionMetadata.findMany({
   658→        where:   { sessionId },
   659→        orderBy: { createdAt: "asc" },
   660→        include: {
   661→          ...V2_SESSION_INCLUDE,
   662→          tokenUsage:   true,
   663→          filesTouched: { include: { filePath: true } },
   664→        },
   665→      });
   666→
   667→      res.json(sessionRows.map((s) => ({
   668→        checkpointId: s.checkpointId,
   669→        cliVersion:   s.cliVersion,
   670→        branch:       s.branch,
   671→        createdAt:    s.createdAt?.toISOString() ?? null,
   672→        tokenUsage:   s.tokenUsage ? {
   673→          inputTokens:         s.tokenUsage.inputTokens,
   674→          cacheCreationTokens: s.tokenUsage.cacheCreationTokens,
   675→          cacheReadTokens:     s.tokenUsage.cacheReadTokens,
   676→          outputTokens:        s.tokenUsage.outputTokens,
   677→          apiCallCount:        s.tokenUsage.apiCallCount,
   678→        } : null,
   679→        filesTouched: s.filesTouched.map((f) => f.filePath.path),
   680→        summary:      s.summary ? mapV2Summary(s.summary) : null,
   681→      })));
   682→    } catch (err) {
   683→      res.status(500).json({ error: String(err) });
   684→    }
   685→  });
   686→
   687→  // PATCH /api/open-items/:id
   688→  app.patch("/api/open-items/:id", async (req, res) => {
   689→    const id = parseInt(req.params.id, 10);
   690→    const { status, subSessionId } = req.body as { status?: string; subSessionId?: string };
   691→    const allowed = ["open", "in_progress", "complete", "na"];
   692→    if (status !== undefined && !allowed.includes(status)) {
   693→      res.status(400).json({ error: "status must be open, in_progress, or complete" });
   694→      return;
   695→    }
   696→    try {
   697→      const updated = await db.openItem.update({
   698→        where: { id },
   699→        data: {
   700→          ...(status !== undefined ? { status } : {}),
   701→          ...(subSessionId !== undefined ? { subSessionId } : {}),
   702→        },
   703→      });
   704→      res.json({ id: updated.id, status: updated.status, subSessionId: updated.subSessionId });
   705→    } catch (err) {
   706→      res.status(500).json({ error: String(err) });
   707→    }
   708→  });
   709→
   710→  // POST /api/sessions/spawn
   711→  app.post("/api/sessions/spawn", async (req, res) => {
   712→    const { prompt, cwd, openItemIds, parentSessionId } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[]; parentSessionId?: string };
   713→    if (!prompt || typeof prompt !== "string") {
   714→      res.status(400).json({ error: "prompt is required" });
   715→      return;
   716→    }
   717→    try {
   718→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   719→      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   720→      // Pass open item IDs and parent session so the SessionStart hook can link back
   721→      const envParts: string[] = [];
   722→      if (openItemIds?.length) envParts.push(`GOSSAMER_SPAWN_OPEN_ITEMS='${openItemIds.join(",")}'`);
   723→      if (parentSessionId) envParts.push(`GOSSAMER_SPAWN_PARENT_SESSION='${parentSessionId.replace(/'/g, "")}'`);
   724→      const envPrefix = envParts.length ? envParts.join(" ") + " " : "";
   725→      // Use AppleScript to open a new Terminal window running claude interactively
   726→      const script = [
   727→        `tell application "Terminal"`,
   728→        `  activate`,
   729→        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   730→        `end tell`,
   731→      ].join("\n");
   732→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   733→      // Mark selected open items as in_progress
   734→      if (openItemIds?.length) {
   735→        await db.openItem.updateMany({
   736→          where: { id: { in: openItemIds } },
   737→          data: { status: "in_progress" },
   738→        });
   739→      }
   740→      res.json({ started: true });
   741→    } catch (err) {
   742→      res.status(500).json({ error: String(err) });
   743→    }
   744→  });
   745→
   746→  // GET /api/search?q=TEXT[&limit=N]
   747→  app.get("/api/search", async (req, res) => {
   748→    const q     = typeof req.query.q     === "string" ? req.query.q.trim()         : "";
   749→    const limit = typeof req.query.limit === "string" ? parseInt(req.query.limit)  : 50;
   750→    if (!q) { res.status(400).json({ error: "q is required" }); return; }
   751→    try {
   752→      const results = await searchLogContent(db, q, Math.min(limit, 200));
   753→      res.json(results);
   754→    } catch (err) {
   755→      // FTS5 MATCH errors (bad syntax) come back as exceptions
   756→      res.status(400).json({ error: String(err) });
   757→    }
   758→  });
   759→
   760→  // Create HTTP server and attach WebSocket server (shared port)
   761→  const httpServer = createServer(app);
   762→  const wss = new WebSocketServer({ server: httpServer });
   763→
   764→  // WebSocket change detection — poll every 2s, broadcast on new log events, checkpoints, or shadow sessions
   765→  let lastMaxLogEventId: number | null = null;
   766→  let lastMaxCheckpointId: number | null = null;
   767→  let lastMaxShadowSessionId: number | null = null;
   768→  const broadcast = () => {
   769→    const message = JSON.stringify({ type: "sessions_updated" });
   770→    for (const client of wss.clients) {
   771→      if (client.readyState === WebSocket.OPEN) {
   772→        client.send(message);
   773→      }
   774→    }
   775→  };
   776→  const poller = setInterval(async () => {
   777→    try {
   778→      const [latestLogEvent, latestCheckpoint, latestShadow] = await Promise.all([
   779→        db.logEvent.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   780→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   781→        db.shadowSession.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   782→      ]);
   783→      const curLogEvent   = latestLogEvent?.id   ?? null;
   784→      const curCheckpoint = latestCheckpoint?.id ?? null;
   785→      const curShadow     = latestShadow?.id     ?? null;
   786→      if (curLogEvent !== lastMaxLogEventId || curCheckpoint !== lastMaxCheckpointId || curShadow !== lastMaxShadowSessionId) {
   787→        lastMaxLogEventId   = curLogEvent;
   788→        lastMaxCheckpointId = curCheckpoint;
   789→        lastMaxShadowSessionId = curShadow;
   790→        broadcast();
   791→      }
   792→    } catch {
   793→      // Non-fatal polling error — keep running
   794→    }
   795→  }, 2000);
   796→
   797→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   798→
   799→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   800→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   801→
   802→  if (repoDir) {
   803→    const WORKTREE_PATH = join(repoDir, ".gossamer", "checkpoints");
   804→    mkdirSync(join(repoDir, ".gossamer"), { recursive: true });
   805→
   806→    // Ensure worktree exists (reuse across restarts)
   807→    if (!existsSync(WORKTREE_PATH)) {
   808→      try {
   809→        // Prune stale worktree registration first, then re-add
   810→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   811→        execSync(
   812→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   813→          { stdio: "pipe" },
   814→        );
   815→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   816→      } catch (err) {
   817→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   818→      }
   819→    }
   820→
   821→    const runIndex = async () => {
   822→      if (!existsSync(WORKTREE_PATH)) return;
   823→      try {
   824→        // Try to fetch from remote first (may fail if SSH unavailable — non-fatal).
   825→        // Always reset to the local branch tip, which entire updates locally on commit.
   826→        try {
   827→          execSync(
   828→            `git -C ${JSON.stringify(WORKTREE_PATH)} fetch origin ${CHECKPOINT_BRANCH}`,
   829→            { stdio: "pipe" },
   830→          );
   831→        } catch { /* remote unavailable — local commits still present */ }
   832→        execSync(
   833→          `git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard ${CHECKPOINT_BRANCH}`,
   834→          { stdio: "pipe" },
   835→        );
   836→      } catch { /* non-fatal */ }
   837→      try {
   838→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH, undefined, repoDir);
   839→        if (checkpoints > 0) {
   840→          process.stderr.write(`checkpoint indexer: indexed ${checkpoints} checkpoints\n`);
   841→          broadcast();
   842→        }
   843→      } catch { /* non-fatal */ }
   844→    };
   845→
   846→    void runIndex();
   847→    checkpointPoller = setInterval(runIndex, 30_000);
   848→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   849→  }
   850→
   851→  // ── Shadow branch indexer ──────────────────────────────────────────────────
   852→
   853→  let shadowPoller: ReturnType<typeof setInterval> | null = null;
   854→
   855→  if (repoDir) {
   856→    const runShadowIndex = async () => {
   857→      try {
   858→        const { sessions } = await indexAllShadowBranches(db, repoDir);
   859→        if (sessions > 0) broadcast();
   860→      } catch { /* non-fatal */ }
   861→    };
   862→
   863→    void runShadowIndex();
   864→    shadowPoller = setInterval(runShadowIndex, 5_000);
   865→    process.stderr.write(`shadow indexer: polling every 5s (repo: ${repoDir})\n`);
   866→  }
   867→
   868→  // Graceful shutdown
   869→  const shutdown = () => {
   870→    clearInterval(poller);
   871→    if (checkpointPoller) clearInterval(checkpointPoller);
   872→    if (shadowPoller) clearInterval(shadowPoller);
   873→    httpServer.close();
   874→    process.exit(0);
   875→  };
   876→  process.on("SIGINT", shutdown);
   877→  process.on("SIGTERM", shutdown);
   878→
   879→  await new Promise<void>((resolve) => {
   880→    httpServer.listen(port, () => {
   881→      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   882→      resolve();
   883→    });
   884→  });
   885→}
   886→

