   137→  if (first) {
   138→    result.push({ id: id--, timestamp: first.timestamp ?? "", event: "SessionStart", sessionId: first.sessionId ?? "", blocked: false, data: { cwd: first.cwd ?? "" }, summary: null, keywords: [] });
   139→  }
   140→
   141→  for (const le of filtered) {
   142→    const ts  = le.timestamp ?? "";
   143→    const sid = le.sessionId ?? "";
   144→
   145→    if (le.type === "user") {
   146→      const toolResults = le.contents.filter((c) => c.contentType === "tool_result");
   147→      const textBlocks  = le.contents.filter((c) => c.contentType === "text");
   148→
   149→      if (toolResults.length > 0) {
   150→        for (const tr of toolResults) {
   151→          const failed = tr.isError === true;
   152→          result.push({
   153→            id: id--,
   154→            timestamp: ts,
   155→            event: failed ? "PostToolUseFailure" : "PostToolUse",
   156→            sessionId: sid,
   157→            blocked: false,
   158→            data: {
   159→              tool_use_id:   tr.toolUseId,
   160→              tool_response: !failed ? (tr.toolResultContent ?? "") : undefined,
   161→              error:          failed ? (tr.toolResultContent ?? "") : undefined,
   162→            },
   163→            summary: null, keywords: [],
   164→          });
   165→        }
   166→      } else if (textBlocks.length > 0) {
   167→        const prompt = textBlocks.map((b) => b.text ?? "").join("\n\n");
   168→        result.push({ id: id--, timestamp: ts, event: "UserPromptSubmit", sessionId: sid, blocked: false, data: { prompt }, summary: null, keywords: [] });
   169→      }
   170→
   171→    } else if (le.type === "assistant") {
   172→      const toolUses   = le.contents.filter((c) => c.contentType === "tool_use");
   173→      const textBlocks = le.contents.filter((c) => c.contentType === "text");
   174→
   175→      if (textBlocks.length > 0) {
   176→        lastAssistantText = textBlocks.map((b) => b.text ?? "").filter(Boolean).join("\n\n");
   177→      }
   178→
   179→      for (const tu of toolUses) {
