   221→
   222→function groupEvents(events: Event[]): DisplayItem[] {
   223→  const postMap = new Map<string, Event>();
   224→  for (const event of events) {
   225→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
   226→      const d = event.data as Record<string, unknown>;
   227→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
