   235→
   236→  const raw: RawItem[] = [];
   237→  const consumed = new Set<number>();
   238→
   239→  for (const event of events) {
   240→    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
   241→    if (event.event === "PreToolUse") {
   242→      const d = event.data as Record<string, unknown>;
   243→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   244→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
   245→      if (post) consumed.add(post.id);
   246→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
   247→      continue;
   248→    }
   249→    raw.push({ kind: "event", event });
   250→  }
   251→
   252→  const isGroupable = (item: RawItem) =>
   253→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
   254→
   255→  const result: DisplayItem[] = [];
   256→  let i = 0;
   257→  while (i < raw.length) {
   258→    if (isGroupable(raw[i])) {
   259→      const group: ToolUseData[] = [];
   260→      while (i < raw.length && isGroupable(raw[i])) {
   261→        const item = raw[i];
   262→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
   263→        i++;
   264→      }
   265→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
   266→    } else {
   267→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
   268→      i++;
   269→    }
   270→  }
   271→  return result;
   272→}
