// ── Snippet renderer (for search match annotation) ────────────────────────────

function SnippetHighlight({ raw }: { raw: string }) {
  const parts = raw.split(/(«[^»]*»)/g);
  return (
    <Text size="xs" ff="monospace" style={{ whiteSpace: "pre-wrap", wordBreak: "break-all", lineHeight: 1.5 }}>
