   126→function logEventsToEvents(logEvents: LogEventItem[]): Event[] {
   127→  const result: Event[] = [];
   128→  let id = -1;
   129→  let lastAssistantText: string | null = null;
   130→  let lastAssistantLogEventId: number | null = null;
   131→
   132→  const filtered = logEvents.filter(
   133→    (e) => !e.isSidechain && e.type !== "file-history-snapshot" && e.type !== "progress",
   134→  );
   135→
   136→  // Virtual SessionStart divider
   137→  const first = filtered[0];
   138→  if (first) {
   139→    result.push({ id: id--, timestamp: first.timestamp ?? "", event: "SessionStart", sessionId: first.sessionId ?? "", blocked: false, data: { cwd: first.cwd ?? "" }, summary: null, keywords: [], _sourceLogEventId: first.id });
   140→  }
   141→
   142→  for (const le of filtered) {
   143→    const ts  = le.timestamp ?? "";
   144→    const sid = le.sessionId ?? "";
   145→
   146→    if (le.type === "user") {
   147→      const toolResults = le.contents.filter((c) => c.contentType === "tool_result");
   148→      const textBlocks  = le.contents.filter((c) => c.contentType === "text");
   149→
   150→      if (toolResults.length > 0) {
   151→        for (const tr of toolResults) {
   152→          const failed = tr.isError === true;
   153→          result.push({
   154→            id: id--,
   155→            timestamp: ts,
   156→            event: failed ? "PostToolUseFailure" : "PostToolUse",
   157→            sessionId: sid,
   158→            blocked: false,
   159→            data: {
   160→              tool_use_id:   tr.toolUseId,
   161→              tool_response: !failed ? (tr.toolResultContent ?? "") : undefined,
   162→              error:          failed ? (tr.toolResultContent ?? "") : undefined,
   163→            },
   164→            summary: null, keywords: [], _sourceLogEventId: le.id,
   165→          });
   166→        }
   167→      } else if (textBlocks.length > 0) {
   168→        const prompt = textBlocks.map((b) => b.text ?? "").join("\n\n");
   169→        result.push({ id: id--, timestamp: ts, event: "UserPromptSubmit", sessionId: sid, blocked: false, data: { prompt }, summary: null, keywords: [], _sourceLogEventId: le.id });
   170→      }
   171→
   172→    } else if (le.type === "assistant") {
   173→      const toolUses   = le.contents.filter((c) => c.contentType === "tool_use");
   174→      const textBlocks = le.contents.filter((c) => c.contentType === "text");
   175→
   176→      if (textBlocks.length > 0) {
   177→        lastAssistantText = textBlocks.map((b) => b.text ?? "").filter(Boolean).join("\n\n");
   178→        lastAssistantLogEventId = le.id;
   179→      }
   180→
   181→      for (const tu of toolUses) {
   182→        result.push({
   183→          id: id--,
   184→          timestamp: ts,
   185→          event: "PreToolUse",
   186→          sessionId: sid,
   187→          blocked: false,
   188→          data: { tool_name: tu.toolName ?? "?", tool_use_id: tu.toolUseId, tool_input: tu.toolInput },
   189→          summary: null, keywords: [], _sourceLogEventId: le.id,
   190→        });
   191→      }
   192→
   193→    } else if (le.type === "system" && le.systemData?.subtype === "stop_hook_summary") {
   194→      result.push({
   195→        id: id--,
   196→        timestamp: ts,
   197→        event: "Stop",
   198→        sessionId: sid,
   199→        blocked: le.systemData.preventedContinuation ?? false,
   200→        data: { last_assistant_message: lastAssistantText ?? "", reason: le.systemData.stopReason ?? "" },
   201→        // Point to the assistant event that holds the text — that's what search indexes
   202→        summary: null, keywords: [], _sourceLogEventId: lastAssistantLogEventId ?? le.id,
   203→      });
   204→      lastAssistantText = null;
   205→      lastAssistantLogEventId = null;
   206→    }
   207→  }
   208→
   209→  // Flush any trailing assistant text that had no stop event
   210→  if (lastAssistantText !== null && filtered.length > 0) {
   211→    const last = filtered[filtered.length - 1];
   212→    result.push({
   213→      id: id--,
   214→      timestamp: last.timestamp ?? "",
   215→      event: "Stop",
   216→      sessionId: last.sessionId ?? "",
   217→      blocked: false,
   218→      data: { last_assistant_message: lastAssistantText, reason: "" },
   219→      summary: null, keywords: [], _sourceLogEventId: lastAssistantLogEventId ?? last.id,
   220→    });
   221→  }
   222→
   223→  return result;
   224→}
