   226→function groupEvents(events: Event[]): DisplayItem[] {
   227→  const postMap = new Map<string, Event>();
   228→  for (const event of events) {
   229→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
   230→      const d = event.data as Record<string, unknown>;
   231→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   232→      if (id) postMap.set(id, event);
   233→    }
   234→  }
   235→
   236→  type RawItem =
   237→    | { kind: "event"; event: Event }
   238→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
   239→
   240→  const raw: RawItem[] = [];
   241→  const consumed = new Set<number>();
   242→
   243→  for (const event of events) {
   244→    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
   245→    if (event.event === "PreToolUse") {
   246→      const d = event.data as Record<string, unknown>;
   247→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   248→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
   249→      if (post) consumed.add(post.id);
   250→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
   251→      continue;
   252→    }
   253→    raw.push({ kind: "event", event });
   254→  }
   255→
   256→  const isGroupable = (item: RawItem) =>
   257→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
   258→
   259→  const result: DisplayItem[] = [];
   260→  let i = 0;
   261→  while (i < raw.length) {
   262→    if (isGroupable(raw[i])) {
   263→      const group: ToolUseData[] = [];
   264→      while (i < raw.length && isGroupable(raw[i])) {
   265→        const item = raw[i];
   266→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
   267→        i++;
   268→      }
   269→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
   270→    } else {
   271→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
   272→      i++;
   273→    }
   274→  }
   275→  return result;
   276→}
