   340→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>△ Friction</Text>
   341→              {sum.friction.map((it, i) => <Text key={i} size="xs">· {it}</Text>)}
   342→            </Box>
   343→          ) : null}
   344→          {sum?.openItems?.length ? (
   345→            <Box>
   346→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>◇ Open items</Text>
   347→              {sum.openItems.map((it, i) => <Text key={i} size="xs">· {it.text}</Text>)}
   348→            </Box>
   349→          ) : null}
   350→          {fileCount > 0 && (
   351→            <Box>
   352→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>Files touched</Text>
   353→              {checkpoint.filesTouched.map((f, i) => <Text key={i} size="xs" ff="monospace" c="dimmed" pl={4}>{f}</Text>)}
   354→            </Box>
   355→          )}
   356→          <UnstyledButton
   357→            onClick={onPress}
   358→            style={{ alignSelf: "flex-start", marginTop: 4, padding: "5px 10px", borderRadius: 4, border: "1px solid var(--mantine-color-teal-3)" }}
   359→          >
   360→            <Text size="xs" c="teal" ff="monospace">Open checkpoint →</Text>
   361→          </UnstyledButton>
   362→        </Box>
   363→      </Collapse>
   364→    </Box>
   365→    </Box>
   366→  );
   367→}
   368→
   369→// ── Snippet renderer (for search match annotation) ────────────────────────────
   370→
   371→function SnippetHighlight({ raw }: { raw: string }) {
   372→  const parts = raw.split(/(«[^»]*»)/g);
   373→  return (
   374→    <Text size="xs" ff="monospace" style={{ whiteSpace: "pre-wrap", wordBreak: "break-all", lineHeight: 1.5 }}>
   375→      {parts.map((part, i) =>
   376→        part.startsWith("«") && part.endsWith("»") ? (
   377→          <Text key={i} component="span" size="xs" fw={700} style={{ backgroundColor: "rgba(255,200,0,0.35)", borderRadius: 2, padding: "0 2px" }} ff="monospace">
   378→            {part.slice(1, -1)}
   379→          </Text>
   380→        ) : part
   381→      )}
   382→    </Text>
   383→  );
   384→}
   385→
   386→// ── Source log event ID extractor ─────────────────────────────────────────────
   387→
   388→function getItemSourceIds(item: RenderItem): number[] {
   389→  if (item.kind === "event") {
   390→    return item.event._sourceLogEventId != null ? [item.event._sourceLogEventId] : [];
   391→  }
   392→  if (item.kind === "claudeTurn") {
   393→    const ids: number[] = [];
   394→    for (const group of item.toolGroups) {
   395→      for (const tool of group) {
   396→        if (tool.pre._sourceLogEventId != null) ids.push(tool.pre._sourceLogEventId);
   397→        if (tool.post?._sourceLogEventId != null) ids.push(tool.post._sourceLogEventId);
   398→      }
   399→    }
   400→    if (item.stop?._sourceLogEventId != null) ids.push(item.stop._sourceLogEventId);
   401→    return ids;
   402→  }
   403→  return [];
   404→}
