   406→export function SessionDetail() {
   407→  const navigate = useNavigate();
   408→  const { sessionId } = useParams<{ sessionId: string }>();
   409→  const [searchParams] = useSearchParams();
   410→  const location = useLocation();
   411→  const targetLogEventId = searchParams.get("logEventId") ? parseInt(searchParams.get("logEventId")!) : null;
   412→  const searchSnippet = (location.state as { snippet?: string } | null)?.snippet ?? null;
   413→  const [highlightActive, setHighlightActive] = useState(false);
   414→  const scrolledRef = useRef(false);
   415→  const [session, setSession] = useState<Session | null>(null);
   416→  const [latestCheckpoint, setLatestCheckpoint] = useState<SessionCheckpoint | null>(null);
   417→  const [items, setItems] = useState<RenderItem[]>([]);
   418→  const [userInfo, setUserInfo] = useState<UserInfo | undefined>(undefined);
   419→  const [openItems, setOpenItems] = useState<OpenItem[]>([]);
   420→  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
   421→  const [spawning, setSpawning] = useState(false);
   422→  const [loading, setLoading] = useState(true);
   423→  const [error, setError] = useState<string | null>(null);
   424→
   425→  const id = sessionId!;
   426→  const { setCrumbs } = useBreadcrumb();
   427→
   428→  function applyCheckpoints(logEvs: LogEventItem[], checkpoints: SessionCheckpoint[]) {
   429→    const grouped = groupEvents(logEventsToEvents(logEvs));
   430→    const merged: DisplayItem[] = [];
   431→    let cpIdx = 0;
   432→    const sortedCps = [...checkpoints].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   433→    const latest = sortedCps[sortedCps.length - 1] ?? null;
   434→    setLatestCheckpoint(latest);
   435→    setOpenItems(latest?.summary?.openItems ?? []);
   436→
   437→    for (const item of grouped) {
   438→      const itemTime = item.kind === "event" ? item.event.timestamp : item.kind === "toolGroup" ? item.tools[0]?.pre.timestamp ?? "" : "";
   439→      while (cpIdx < sortedCps.length && (sortedCps[cpIdx].createdAt ?? "") <= itemTime) {
   440→        merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   441→      }
   442→      merged.push(item);
   443→    }
   444→    while (cpIdx < sortedCps.length) merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   445→    setItems(groupClaudeTurns(merged));
   446→  }
   447→
   448→  // Initial load
   449→  useEffect(() => {
   450→    Promise.all([fetchSession(id), fetchLogEvents(id), fetchSessionCheckpoints(id)])
   451→      .then(([s, logEvs, checkpoints]) => {
   452→        setSession(s);
   453→        const user = s.gitUserName ?? s.gitUserEmail ?? null;
   454→        const repo = s.repoName ?? null;
   455→        const shortId = s.sessionId.slice(0, 8) + "…";
   456→        if (user) {
   457→          setUserInfo({
   458→            name: s.gitUserName ?? user,
   459→            avatarUrl: s.gitUserName ? `https://github.com/${s.gitUserName}.png?size=40` : undefined,
   460→          });
   461→        }
   462→        setCrumbs([
   463→          ...(user ? [{ label: user, path: "/" }] : []),
   464→          ...(repo ? [{ label: repo, path: "/" }] : []),
   465→          { label: shortId },
   466→        ]);
   467→        applyCheckpoints(logEvs, checkpoints);
   468→        setError(null);
   469→      })
   470→      .catch((err: unknown) => setError(String(err)))
   471→      .finally(() => setLoading(false));
   472→  }, [id]);
   473→
   474→  // Live updates: re-fetch checkpoints and log events when the server broadcasts a change
   475→  useEffect(() => {
   476→    return subscribeToUpdates(() => {
   477→      Promise.all([fetchLogEvents(id), fetchSessionCheckpoints(id)])
   478→        .then(([logEvs, checkpoints]) => applyCheckpoints(logEvs, checkpoints))
   479→        .catch(() => undefined);
   480→    });
   481→  }, [id]);
   482→
   483→  // Scroll to and highlight the target log event from a search result
   484→  useEffect(() => {
   485→    if (targetLogEventId === null || items.length === 0 || scrolledRef.current) return;
   486→    const timer = setTimeout(() => {
   487→      const el = document.querySelector(`[data-log-event-id="${targetLogEventId}"]`);
   488→      if (el) {
   489→        el.scrollIntoView({ behavior: "smooth", block: "center" });
   490→        setHighlightActive(true);
   491→        scrolledRef.current = true;
   492→        setTimeout(() => setHighlightActive(false), 2500);
   493→      }
   494→    }, 150);
   495→    return () => clearTimeout(timer);
   496→  }, [items, targetLogEventId]);
   497→
   498→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="indigo" /></Center>;
   499→  if (error) return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
   500→
   501→  return (
   502→    <ScrollArea style={{ flex: 1 }}>
   503→      <Box style={{ maxWidth: 860, margin: "0 auto", paddingBottom: 40 }}>
   504→      {session?.parentSessionId && (
   505→        <UnstyledButton
   506→          onClick={() => navigate(`/sessions/${session.parentSessionId}`, { state: { title: session.parentSessionId!.slice(0, 8) + "…" } })}
   507→          style={{ width: "100%", display: "flex", alignItems: "center", gap: 6, backgroundColor: "light-dark(var(--mantine-color-blue-0), var(--mantine-color-dark-6))", borderBottom: "1px solid var(--mantine-color-blue-2)", padding: "8px 14px" }}
   508→        >
   509→          <Text size="xs" c="blue">↑ Continuation of</Text>
   510→          <Text size="xs" c="blue" ff="monospace" fw={600} td="underline">{session.parentSessionId.slice(0, 8)}…</Text>
   511→        </UnstyledButton>
   512→      )}
   513→      {session?.childSessionIds?.map((childId) => (
   514→        <UnstyledButton
   515→          key={childId}
   516→          onClick={() => navigate(`/sessions/${childId}`, { state: { title: childId.slice(0, 8) + "…" } })}
   517→          style={{ width: "100%", display: "flex", alignItems: "center", gap: 6, backgroundColor: "light-dark(var(--mantine-color-green-0), var(--mantine-color-dark-6))", borderBottom: "1px solid var(--mantine-color-green-2)", padding: "8px 14px" }}
   518→        >
   519→          <Text size="xs" c="green">↓ Continued as</Text>
   520→          <Text size="xs" c="green" ff="monospace" fw={600} td="underline">{childId.slice(0, 8)}…</Text>
   521→        </UnstyledButton>
   522→      ))}
   523→
   524→      {latestCheckpoint?.summary && (
   525→        <Box style={{
   526→          borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
   527→          padding: "16px 20px",
   528→          backgroundColor: "light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-7))",
   529→        }}>
   530→          <Text size="sm" fw={600} lh={1.5} mb={latestCheckpoint.summary.openItems?.length ? 12 : 0}>
   531→            {latestCheckpoint.summary.intent}
   532→          </Text>
   533→          {openItems.length > 0 && (
   534→            <Box>
   535→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={8} style={{ letterSpacing: 0.5 }}>
   536→                Open items
   537→              </Text>
   538→              {openItems.map((item, i) => {
   539→                const selectable = item.status === "open";
   540→                const statusColor = item.status === "complete" ? "teal" : item.status === "in_progress" ? "orange" : item.status === "na" ? "gray" : "blue";
   541→                const statusLabel = item.status === "in_progress" ? "in progress" : item.status === "na" ? "n/a" : item.status;
   542→                return (
   543→                  <Group key={item.id} gap={10} align="flex-start" mb={6} wrap="nowrap">
   544→                    {selectable ? (
   545→                      <Checkbox
   546→                        size="xs"
   547→                        radius="xl"
   548→                        checked={selectedItems.has(i)}
   549→                        onChange={(e) => {
   550→                          setSelectedItems((prev) => {
   551→                            const next = new Set(prev);
   552→                            e.currentTarget.checked ? next.add(i) : next.delete(i);
   553→                            return next;
   554→                          });
   555→                        }}
   556→                        onClick={(e) => e.stopPropagation()}
   557→                        style={{ marginTop: 2, flexShrink: 0 }}
   558→                      />
   559→                    ) : (
   560→                      <Box style={{ width: 16, flexShrink: 0 }} />
   561→                    )}
   562→                    <Menu withinPortal position="bottom-start" shadow="sm">
   563→                      <Menu.Target>
   564→                        <Badge
   565→                          color={statusColor}
   566→                          size="xs"
   567→                          variant="light"
   568→                          style={{ cursor: "pointer", flexShrink: 0, marginTop: 2, textTransform: "none" }}
   569→                        >
   570→                          {statusLabel}
   571→                        </Badge>
   572→                      </Menu.Target>
   573→                      <Menu.Dropdown>
   574→                        {(["open", "in_progress", "complete", "na"] as const).map((s) => (
   575→                          <Menu.Item
   576→                            key={s}
   577→                            fw={item.status === s ? 700 : undefined}
   578→                            onClick={async () => {
   579→                              await updateOpenItemStatus(item.id, s).catch(() => undefined);
   580→                              setOpenItems((prev) => prev.map((it) => it.id === item.id ? { ...it, status: s } : it));
   581→                              if (s !== "open") setSelectedItems((prev) => { const n = new Set(prev); n.delete(i); return n; });
   582→                            }}
   583→                          >
   584→                            {s === "in_progress" ? "in progress" : s === "na" ? "n/a" : s}
   585→                          </Menu.Item>
   586→                        ))}
   587→                      </Menu.Dropdown>
   588→                    </Menu>
   589→                    <Text size="xs" lh={1.5} c={selectable ? undefined : "dimmed"} style={{ cursor: "default" }}>{item.text}</Text>
   590→                  </Group>
   591→                );
   592→              })}
   593→              {selectedItems.size > 0 && (
   594→                <Group gap={8} mt={10}>
   595→                  <Text size="xs" c="dimmed">Work on selection in new session?</Text>
   596→                  <Tooltip label={spawning ? "Starting…" : "Start new Claude session"} withArrow>
   597→                    <ActionIcon
   598→                      size="sm"
   599→                      variant="light"
   600→                      color="indigo"
   601→                      loading={spawning}
   602→                      onClick={async () => {
   603→                        if (!session?.cwd) return;
   604→                        const selected = openItems.filter((_, i) => selectedItems.has(i));
   605→                        const lines = selected.map((item) => `- ${item.text}`).join("\n");
   606→                        const prompt = `Please work on the following open items:\n${lines}`;
   607→                        setSpawning(true);
   608→                        try {
   609→                          await spawnSession(prompt, session.cwd, selected.map((it) => it.id), session.sessionId);
   610→                          const selectedIds = new Set(selected.map((it) => it.id));
   611→                          setOpenItems((prev) => prev.map((it) => selectedIds.has(it.id) ? { ...it, status: "in_progress" as const } : it));
   612→                          setSelectedItems(new Set());
   613→                        } finally {
   614→                          setSpawning(false);
   615→                        }
   616→                      }}
   617→                    >
   618→                      →
   619→                    </ActionIcon>
   620→                  </Tooltip>
   621→                </Group>
   622→              )}
   623→            </Box>
