   659→                  checkpoint={item.checkpoint}
   660→                  onPress={() => navigate(`/checkpoints/${item.checkpoint.checkpointId}`, {
   661→                    state: { title: item.checkpoint.branch ? `${item.checkpoint.branch} · ${item.checkpoint.checkpointId}` : item.checkpoint.checkpointId },
   662→                  })}
   663→                />
   664→              ) : (
   665→                <EventItem event={item.event} user={userInfo} />
