            <Box>
              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>{"</>"} Code learnings</Text>
              {sum.codeLearnings.map((it, i) => (
                <Box key={i} pl={4} mb={2}>
                  <Text size="xs" ff="monospace" c="violet" fw={600}>{it.path}</Text>
