export function MarkdownView({ text }: { text: string }) {
  const blocks = useMemo(() => parseBlocks(text), [text]);

  return (
    <div style={{ fontSize: 13, color: "light-dark(#374151, var(--mantine-color-dark-0))", lineHeight: "20px" }}>
