              <pre style={{ margin: 0, fontFamily: "monospace", fontSize: 12, color: "light-dark(#334155, #e2e8f0)", lineHeight: "18px", whiteSpace: "pre-wrap", wordBreak: "break-all" }}>{block.code}</pre>
            </div>
          );
        }
        if (block.kind === "h") {
          const Tag = `h${block.level}` as "h1" | "h2" | "h3";
